window.COURSE_REGISTRY = window.COURSE_REGISTRY || {};
window.COURSE_REGISTRY["cslb-law"] = [{"id": 1, "sec": "Licensing Requirements", "q": "In California, a contractor's license is generally required when the combined cost of labor and materials on a project is at least:", "opts": ["$200", "$500", "$1,000", "$2,500"], "correct": 1, "re": "Work valued at $500 or more (labor + materials) requires a license; below that is the 'minor work' exemption — but the job can't be split to dodge the limit.", "rr": "Работа на $500 и больше (труд + материалы) требует лицензии; ниже — исключение 'minor work'. Дробить заказ ради обхода лимита нельзя."}, {"id": 2, "sec": "Licensing Requirements", "q": "The minimum age to apply for a contractor's license in California is:", "opts": ["16", "18", "21", "25"], "correct": 1, "re": "Applicants must be at least 18 years old.", "rr": "Заявителю должно быть не меньше 18 лет."}, {"id": 3, "sec": "Licensing Requirements", "q": "A contractor's bond required of most active California licensees is in the amount of:", "opts": ["$12,500", "$15,000", "$25,000", "$100,000"], "correct": 2, "re": "The contractor's bond is $25,000 (raised from $15,000 effective Jan 1, 2023).", "rr": "Облигация контрактора — $25,000 (повышена с $15,000 с 1 января 2023). Проверь актуальную сумму."}, {"id": 4, "sec": "Licensing Requirements", "q": "How often must a California contractor's license be renewed?", "opts": ["Every year", "Every 2 years", "Every 3 years", "Every 5 years"], "correct": 1, "re": "Active and inactive licenses renew every two years.", "rr": "Активная и неактивная лицензии продлеваются каждые 2 года."}, {"id": 5, "sec": "Licensing Requirements", "q": "A licensee must notify the CSLB of a change of business address within:", "opts": ["10 days", "30 days", "90 days", "6 months"], "correct": 2, "re": "Address changes must be reported to the Board within 90 days.", "rr": "О смене адреса нужно уведомить CSLB в течение 90 дней."}, {"id": 6, "sec": "Licensing Requirements", "q": "The person who takes and passes the trade and law exams to qualify a license is the:", "opts": ["Registered agent", "Qualifying individual", "Bond guarantor", "Responsible employee"], "correct": 1, "re": "The qualifying individual (RMO or RME) holds the trade knowledge that qualifies the license.", "rr": "Квалифицирующее лицо (RMO или RME) — носитель профессиональных знаний, на которых держится лицензия."}, {"id": 7, "sec": "Licensing Requirements", "q": "An RME (Responsible Managing Employee) must be employed by the licensee at least:", "opts": ["8 hours/week", "16 hours/week or 60% of the business's hours", "32 hours/week", "Full-time only"], "correct": 1, "re": "An RME must work at least 32 hours or 60% of the business's total operating hours per week — whichever is less.", "rr": "RME обязан работать минимум 32 часа или 60% рабочих часов бизнеса в неделю — что меньше."}, {"id": 8, "sec": "Licensing Requirements", "q": "Which business form makes owners personally liable for all business debts?", "opts": ["Corporation", "Limited liability company", "Sole proprietorship", "Limited partnership (limited partners)"], "correct": 2, "re": "A sole proprietor is personally liable for all debts and obligations of the business.", "rr": "Индивидуальный предприниматель лично отвечает по всем долгам и обязательствам бизнеса."}, {"id": 9, "sec": "Licensing Requirements", "q": "A 'Bond of Qualifying Individual' is generally required when the qualifier is:", "opts": ["A sole owner", "An RMO owning 10% or more of the corporation", "An RME or an RMO owning less than 10%", "Any qualifier, always"], "correct": 2, "re": "The qualifier's bond ($25,000) is required for an RME, or an RMO who owns less than 10% of the voting stock.", "rr": "Облигация квалификатора ($25,000) нужна для RME или RMO, владеющего менее 10% голосующих акций."}, {"id": 10, "sec": "Licensing Requirements", "q": "Contracting without a license when one is required is generally a:", "opts": ["Infraction with no penalty", "Misdemeanor", "Felony on first offense", "Civil matter only"], "correct": 1, "re": "Unlicensed contracting is a misdemeanor; penalties escalate on repeat offenses.", "rr": "Работа без лицензии — мисдиминор; за повторные нарушения наказание усиливается."}, {"id": 11, "sec": "Licensing Requirements", "q": "An unlicensed contractor who sues to collect payment for work requiring a license will generally:", "opts": ["Win full payment", "Recover only materials cost", "Be barred from collecting and may have to refund paid amounts", "Recover 50%"], "correct": 2, "re": "B&P Code §7031 bars unlicensed contractors from suing for compensation and lets clients recover what they already paid.", "rr": "§7031 B&P запрещает безлицензионному контрактору взыскивать оплату и позволяет клиенту вернуть уже уплаченное."}, {"id": 12, "sec": "Licensing Requirements", "q": "When the qualifying individual disassociates from a license, the licensee must notify CSLB within:", "opts": ["10 days", "30 days", "90 days", "1 year"], "correct": 2, "re": "Disassociation of the qualifier must be reported within 90 days, or the license may be suspended.", "rr": "Об уходе квалификатора нужно сообщить в течение 90 дней, иначе лицензию могут приостановить."}, {"id": 13, "sec": "Licensing Requirements", "q": "A joint venture license:", "opts": ["Needs no separate registration", "Combines two or more licensees and must itself be licensed", "Is only for public works", "Replaces each partner's individual license"], "correct": 1, "re": "A joint venture of licensed contractors must obtain its own joint venture license number.", "rr": "Совместное предприятие лицензированных контракторов должно получить собственный номер лицензии JV."}, {"id": 14, "sec": "Business Finances", "q": "In a basic accounting equation, Assets equal:", "opts": ["Liabilities − Equity", "Liabilities + Owner's Equity", "Revenue − Expenses", "Equity − Liabilities"], "correct": 1, "re": "Assets = Liabilities + Owner's Equity is the fundamental accounting equation.", "rr": "Активы = Обязательства + Собственный капитал — базовое бухгалтерское уравнение."}, {"id": 15, "sec": "Business Finances", "q": "Money owed TO the business by customers is recorded as:", "opts": ["Accounts payable", "Accounts receivable", "Retained earnings", "Owner's draw"], "correct": 1, "re": "Accounts receivable is money customers owe the business.", "rr": "Accounts receivable — деньги, которые клиенты должны бизнесу."}, {"id": 16, "sec": "Business Finances", "q": "Money the business OWES to suppliers is:", "opts": ["Accounts receivable", "Accounts payable", "Gross profit", "Net worth"], "correct": 1, "re": "Accounts payable is what the business owes others.", "rr": "Accounts payable — то, что бизнес должен другим."}, {"id": 17, "sec": "Business Finances", "q": "Gross profit is calculated as:", "opts": ["Revenue − all expenses", "Revenue − cost of goods sold", "Assets − liabilities", "Net income + taxes"], "correct": 1, "re": "Gross profit = revenue − cost of goods sold, before overhead.", "rr": "Валовая прибыль = выручка − себестоимость, до накладных расходов."}, {"id": 18, "sec": "Business Finances", "q": "Overhead costs are best described as:", "opts": ["Direct labor on a job", "Materials for a specific job", "Ongoing costs not tied to one job (rent, insurance, office)", "Subcontractor invoices"], "correct": 2, "re": "Overhead is indirect cost of running the business, not chargeable to a single job.", "rr": "Накладные — косвенные расходы на ведение бизнеса, не привязанные к одному заказу."}, {"id": 19, "sec": "Business Finances", "q": "A markup of 25% on a $4,000 job cost produces a selling price of:", "opts": ["$4,250", "$4,500", "$5,000", "$5,333"], "correct": 2, "re": "$4,000 × 1.25 = $5,000. (Markup is on cost, not on price.)", "rr": "$4,000 × 1.25 = $5,000. Наценка считается от себестоимости, не от цены."}, {"id": 20, "sec": "Business Finances", "q": "The accounting method that records income when earned and expenses when incurred (not when cash moves) is:", "opts": ["Cash basis", "Accrual basis", "Completed-contract only", "Petty cash"], "correct": 1, "re": "Accrual basis records revenue/expense when earned/incurred, regardless of cash timing.", "rr": "Метод начисления (accrual) фиксирует доход/расход в момент возникновения, независимо от движения денег."}, {"id": 21, "sec": "Business Finances", "q": "A 'current ratio' measures a company's ability to:", "opts": ["Grow long-term", "Pay short-term obligations", "Increase markup", "Reduce taxes"], "correct": 1, "re": "Current ratio = current assets ÷ current liabilities; it gauges short-term liquidity.", "rr": "Current ratio = текущие активы ÷ текущие обязательства; показывает краткосрочную ликвидность."}, {"id": 22, "sec": "Business Finances", "q": "Depreciation on a work truck is:", "opts": ["A cash payment each year", "An allocation of an asset's cost over its useful life", "A type of insurance", "A liability"], "correct": 1, "re": "Depreciation spreads a capital asset's cost across the years it is used.", "rr": "Амортизация распределяет стоимость капитального актива на годы его использования."}, {"id": 23, "sec": "Business Finances", "q": "Working capital equals:", "opts": ["Total assets", "Current assets − current liabilities", "Revenue − overhead", "Equity + debt"], "correct": 1, "re": "Working capital = current assets − current liabilities.", "rr": "Оборотный капитал = текущие активы − текущие обязательства."}, {"id": 24, "sec": "Business Finances", "q": "Which document summarizes income and expenses over a period to show profit or loss?", "opts": ["Balance sheet", "Income (profit & loss) statement", "Bond schedule", "Lien waiver"], "correct": 1, "re": "The income statement (P&L) shows revenue, expenses, and resulting profit/loss for a period.", "rr": "Отчёт о прибылях и убытках (P&L) показывает доходы, расходы и итоговую прибыль/убыток за период."}, {"id": 25, "sec": "Business Finances", "q": "Federal income tax withheld from employee paychecks is:", "opts": ["The employer's expense", "Held in trust and remitted to the IRS", "Optional for small firms", "Refunded to the employer"], "correct": 1, "re": "Withholding is the employee's money held in trust by the employer and paid to the IRS.", "rr": "Удержанный налог — деньги работника, которые работодатель держит в доверии и перечисляет в IRS."}, {"id": 26, "sec": "Business Finances", "q": "FICA taxes fund:", "opts": ["State disability only", "Social Security and Medicare", "Unemployment only", "Workers' compensation"], "correct": 1, "re": "FICA covers Social Security and Medicare, split between employer and employee.", "rr": "FICA финансирует Social Security и Medicare; делится между работодателем и работником."}, {"id": 27, "sec": "Business Finances", "q": "A cash-flow problem most directly means the business:", "opts": ["Is unprofitable", "Lacks cash to meet obligations when due", "Has too many assets", "Pays too little tax"], "correct": 1, "re": "Cash-flow trouble is a timing problem — not enough cash on hand when bills come due, even if profitable.", "rr": "Проблема денежного потока — это вопрос времени: не хватает наличных к сроку оплаты, даже если бизнес прибыльный."}, {"id": 28, "sec": "Employment & Labor", "q": "California workers' compensation insurance is required when a business has:", "opts": ["10 or more employees", "5 or more employees", "Any employees at all", "Only union employees"], "correct": 2, "re": "Any employer with even one employee must carry workers' comp.", "rr": "Любой работодатель, имеющий хотя бы одного работника, обязан иметь workers' comp."}, {"id": 29, "sec": "Employment & Labor", "q": "A licensee with no employees may file with CSLB a:", "opts": ["Performance bond", "Workers' comp exemption certificate", "Lien release", "Notice of completion"], "correct": 1, "re": "A licensee with no employees can certify an exemption from workers' comp.", "rr": "Лицензиат без работников может подать сертификат об освобождении от workers' comp."}, {"id": 30, "sec": "Employment & Labor", "q": "In California, daily overtime (1.5×) generally begins after:", "opts": ["6 hours", "8 hours", "10 hours", "12 hours"], "correct": 1, "re": "Overtime at 1.5× starts after 8 hours in a day (and after 40 in a week).", "rr": "Сверхурочные 1.5× начинаются после 8 часов в день (и после 40 в неделю)."}, {"id": 31, "sec": "Employment & Labor", "q": "Double-time pay (2×) in California is generally required after:", "opts": ["8 hours/day", "10 hours/day", "12 hours/day", "16 hours/day"], "correct": 2, "re": "Double time applies after 12 hours in a workday (and after 8 hours on the 7th consecutive day).", "rr": "Двойная оплата — после 12 часов за смену (и после 8 часов в 7-й день подряд)."}, {"id": 32, "sec": "Employment & Labor", "q": "An employee who is fired must receive their final paycheck:", "opts": ["Within 72 hours", "On the next payday", "Immediately at termination", "Within 30 days"], "correct": 2, "re": "A discharged employee's final wages are due immediately at the time of termination.", "rr": "Уволенному работнику окончательную зарплату обязаны выдать немедленно в момент увольнения."}, {"id": 33, "sec": "Employment & Labor", "q": "An employee who quits without notice must be paid final wages within:", "opts": ["Immediately", "24 hours", "72 hours", "The next payday"], "correct": 2, "re": "For a quit without notice, final wages are due within 72 hours.", "rr": "При увольнении по собственному без предупреждения окончательный расчёт — в течение 72 часов."}, {"id": 34, "sec": "Employment & Labor", "q": "The federal form used to verify a new employee's eligibility to work is:", "opts": ["W-2", "W-4", "I-9", "1099"], "correct": 2, "re": "Form I-9 verifies identity and work authorization for each new hire.", "rr": "Форма I-9 подтверждает личность и право на работу каждого нового сотрудника."}, {"id": 35, "sec": "Employment & Labor", "q": "An employee completes which form to set income-tax withholding?", "opts": ["I-9", "W-4", "W-2", "1099-NEC"], "correct": 1, "re": "The W-4 tells the employer how much income tax to withhold.", "rr": "Форма W-4 указывает работодателю, сколько подоходного налога удерживать."}, {"id": 36, "sec": "Employment & Labor", "q": "A worker paid via Form 1099-NEC is generally treated as a(n):", "opts": ["Employee", "Independent contractor", "Apprentice", "Partner"], "correct": 1, "re": "A 1099-NEC reports payments to an independent contractor, not an employee.", "rr": "1099-NEC отражает оплату независимому подрядчику, а не работнику."}, {"id": 37, "sec": "Employment & Labor", "q": "California's 'ABC test' (AB 5) is used to determine whether a worker is:", "opts": ["Bondable", "An employee or an independent contractor", "Eligible for overtime exemption", "A public works worker"], "correct": 1, "re": "The ABC test presumes a worker is an employee unless all three prongs (A, B, C) are met.", "rr": "Тест ABC презюмирует, что работник — сотрудник, если не выполнены все три условия (A, B, C)."}, {"id": 38, "sec": "Employment & Labor", "q": "New hires must be reported to the EDD New Employee Registry within:", "opts": ["20 days of the start-of-work date", "60 days", "90 days", "Before the first paycheck only"], "correct": 0, "re": "Employers report new hires to the EDD within 20 days.", "rr": "О новых сотрудниках работодатель сообщает в EDD в течение 20 дней."}, {"id": 39, "sec": "Employment & Labor", "q": "State Disability Insurance (SDI) in California is:", "opts": ["Paid entirely by the employer", "Deducted from employee wages", "The same as workers' comp", "Optional"], "correct": 1, "re": "SDI is funded by a deduction from employee wages, administered by the EDD.", "rr": "SDI финансируется удержанием из зарплаты работника, администрируется EDD."}, {"id": 40, "sec": "Employment & Labor", "q": "Federal and state unemployment insurance (FUTA/SUI) is generally:", "opts": ["Withheld from employees", "An employer-paid tax", "Paid by the contractor's client", "Not required in California"], "correct": 1, "re": "Unemployment insurance is an employer cost, not withheld from workers' pay.", "rr": "Страхование по безработице — расход работодателя, не удерживается из зарплаты работника."}, {"id": 41, "sec": "Employment & Labor", "q": "Required meal break for a nonexempt employee working over 5 hours is:", "opts": ["10 minutes", "20 minutes", "30 minutes unpaid", "60 minutes"], "correct": 2, "re": "A 30-minute unpaid meal period is required for shifts over 5 hours.", "rr": "Обеденный перерыв 30 минут (неоплачиваемый) положен при смене свыше 5 часов."}, {"id": 42, "sec": "Employment & Labor", "q": "A paid rest break of 10 minutes is generally required for each:", "opts": ["2 hours worked", "4 hours (or major fraction) worked", "6 hours worked", "8 hours worked"], "correct": 1, "re": "Ten-minute paid rest breaks are required per 4 hours (or major fraction) worked.", "rr": "Оплачиваемый перерыв 10 минут положен на каждые 4 часа (или большую их часть) работы."}, {"id": 43, "sec": "Employment & Labor", "q": "Misclassifying an employee as an independent contractor can result in:", "opts": ["No consequences", "Back taxes, penalties, and liability", "A bonus from EDD", "Automatic license upgrade"], "correct": 1, "re": "Willful misclassification exposes the employer to back taxes, penalties, and wage liability.", "rr": "Сознательная неверная классификация грозит доначислением налогов, штрафами и ответственностью по зарплате."}, {"id": 44, "sec": "Employment & Labor", "q": "The agency that enforces California wage-and-hour laws is the:", "opts": ["CSLB", "DLSE (Labor Commissioner)", "EPA", "DIR Apprenticeship only"], "correct": 1, "re": "The DLSE / Labor Commissioner enforces wage-and-hour law.", "rr": "DLSE / Labor Commissioner следит за соблюдением законов о зарплате и рабочем времени."}, {"id": 45, "sec": "Bonds, Insurance & Liens", "q": "General liability insurance for a contractor primarily covers:", "opts": ["Employee injuries", "Damage or injury the contractor causes to others/property", "The contractor's own tools", "Tax penalties"], "correct": 1, "re": "GL covers third-party bodily injury and property damage caused by the contractor's work.", "rr": "GL покрывает травмы третьих лиц и ущерб имуществу, причинённые работой контрактора."}, {"id": 46, "sec": "Bonds, Insurance & Liens", "q": "Workers' compensation insurance covers:", "opts": ["Damage to a customer's house", "On-the-job injuries to the contractor's employees", "Defective materials", "Contract breach"], "correct": 1, "re": "Workers' comp pays for employees' job-related injuries and illnesses.", "rr": "Workers' comp покрывает производственные травмы и болезни работников."}, {"id": 47, "sec": "Bonds, Insurance & Liens", "q": "A preliminary 20-day notice must generally be served within 20 days of:", "opts": ["Signing the contract", "First furnishing labor or materials", "Project completion", "Recording a lien"], "correct": 1, "re": "The preliminary notice is served within 20 days of first furnishing labor/materials to preserve lien rights.", "rr": "Предварительное уведомление подаётся в течение 20 дней с начала поставки труда/материалов, чтобы сохранить право на lien."}, {"id": 48, "sec": "Bonds, Insurance & Liens", "q": "A mechanics lien is a remedy that attaches to:", "opts": ["The contractor's license", "The improved real property", "The owner's bank account", "The building permit"], "correct": 1, "re": "A mechanics lien attaches to the real property that was improved.", "rr": "Mechanics lien налагается на улучшенную недвижимость."}, {"id": 49, "sec": "Bonds, Insurance & Liens", "q": "If no Notice of Completion is recorded, a direct (prime) contractor must record a mechanics lien within:", "opts": ["30 days of completion", "60 days of completion", "90 days of completion", "1 year of completion"], "correct": 2, "re": "With no NOC, the direct contractor has 90 days after completion to record a lien.", "rr": "Без NOC прямой контрактор должен зарегистрировать lien в течение 90 дней после завершения."}, {"id": 50, "sec": "Bonds, Insurance & Liens", "q": "After recording a mechanics lien, suit to foreclose it must be filed within:", "opts": ["30 days", "60 days", "90 days", "6 months"], "correct": 2, "re": "A foreclosure action on the lien must be filed within 90 days of recording, or the lien expires.", "rr": "Иск об обращении взыскания по lien нужно подать в течение 90 дней после регистрации, иначе lien теряет силу."}, {"id": 51, "sec": "Bonds, Insurance & Liens", "q": "A Notice of Completion is recorded by the owner within how many days of completion?", "opts": ["5 days", "10 days", "15 days", "30 days"], "correct": 2, "re": "The owner records the NOC within 15 days of completion to shorten lien-filing windows.", "rr": "Владелец регистрирует NOC в течение 15 дней после завершения, чтобы сократить сроки подачи lien."}, {"id": 52, "sec": "Bonds, Insurance & Liens", "q": "A bond that protects the owner if the contractor fails to complete the work is a:", "opts": ["Bid bond", "Performance bond", "Payment bond", "License bond"], "correct": 1, "re": "A performance bond guarantees completion of the contract.", "rr": "Performance bond гарантирует выполнение контракта."}, {"id": 53, "sec": "Bonds, Insurance & Liens", "q": "A payment bond guarantees that:", "opts": ["The owner gets a refund", "Subcontractors and suppliers are paid", "The contractor completes on time", "The bid is honored"], "correct": 1, "re": "A payment (labor & material) bond assures subs and suppliers get paid.", "rr": "Payment bond гарантирует оплату субподрядчикам и поставщикам."}, {"id": 54, "sec": "Bonds, Insurance & Liens", "q": "A document by which a claimant gives up lien rights after payment is a:", "opts": ["Stop notice", "Lien release / waiver", "Preliminary notice", "Notice of cessation"], "correct": 1, "re": "A lien waiver/release relinquishes lien rights, typically in exchange for payment.", "rr": "Lien waiver/release отказывается от права на lien, обычно в обмен на оплату."}, {"id": 55, "sec": "Bonds, Insurance & Liens", "q": "To remove a recorded lien from title, an owner may record a surety bond (release bond) for:", "opts": ["50% of the lien", "100% of the lien", "125% of the lien", "200% of the lien"], "correct": 2, "re": "A lien release bond is 125% of the lien amount.", "rr": "Release bond для снятия lien — 125% от суммы lien."}, {"id": 56, "sec": "Bonds, Insurance & Liens", "q": "On private works, the modern equivalent of the old 'stop notice' is the:", "opts": ["Stop payment notice", "Cease-and-desist", "Notice of nonresponsibility", "Mechanics lien"], "correct": 0, "re": "The 'stop payment notice' lets a claimant reach undisbursed construction funds.", "rr": "'Stop payment notice' позволяет претенденту добраться до неосвоенных строительных средств."}, {"id": 57, "sec": "Contracts", "q": "For a contract to be valid, all of the following are required EXCEPT:", "opts": ["Mutual consent (offer & acceptance)", "Consideration", "Lawful object", "A notary's seal"], "correct": 3, "re": "Most contracts need consent, consideration, capacity, and a lawful object — not a notary.", "rr": "Контракту нужны согласие, встречное предоставление, дееспособность и законная цель — нотариус не обязателен."}, {"id": 58, "sec": "Contracts", "q": "A home improvement contract in California must be in writing when it exceeds:", "opts": ["$200", "$500", "$1,000", "$5,000"], "correct": 1, "re": "Home improvement contracts over $500 must be in writing and signed before work begins.", "rr": "Договор на улучшение жилья свыше $500 должен быть письменным и подписанным до начала работ."}, {"id": 59, "sec": "Contracts", "q": "The maximum down payment on a home improvement contract is the lesser of $1,000 or:", "opts": ["5% of the contract", "10% of the contract", "20% of the contract", "25% of the contract"], "correct": 1, "re": "Down payment is capped at the lesser of $1,000 or 10% of the contract price.", "rr": "Аванс ограничен меньшим из: $1,000 или 10% от цены договора."}, {"id": 60, "sec": "Contracts", "q": "A buyer's three-day right to cancel typically applies to:", "opts": ["All contracts", "Home solicitation (door-to-door) contracts", "Public works only", "Verbal contracts"], "correct": 1, "re": "Home-solicitation sales carry a 3-day right of rescission.", "rr": "Сделки, заключённые на дому (door-to-door), дают право отказа в течение 3 дней."}, {"id": 61, "sec": "Contracts", "q": "A change order is best described as:", "opts": ["A new license", "A written modification to the original contract", "A type of bond", "A lien release"], "correct": 1, "re": "A change order documents agreed changes to scope, price, or time — best in writing.", "rr": "Change order фиксирует согласованные изменения объёма, цены или сроков — лучше письменно."}, {"id": 62, "sec": "Contracts", "q": "A contract that cannot legally be enforced by either party is:", "opts": ["Voidable", "Void", "Express", "Implied"], "correct": 1, "re": "A void contract (e.g., for an illegal purpose) has no legal effect from the start.", "rr": "Ничтожный (void) договор — например, на незаконную цель — изначально не имеет юридической силы."}, {"id": 63, "sec": "Contracts", "q": "A voidable contract is one that:", "opts": ["Is illegal", "One party may choose to affirm or cancel", "Needs no consideration", "Is always written"], "correct": 1, "re": "A voidable contract is valid until the party with the right elects to rescind (e.g., a minor's contract).", "rr": "Оспоримый (voidable) договор действителен, пока сторона с правом не решит его расторгнуть (например, договор несовершеннолетнего)."}, {"id": 64, "sec": "Contracts", "q": "A liquidated damages clause specifies:", "opts": ["The bond amount", "Pre-agreed damages for breach (often per day late)", "The down payment", "The warranty period"], "correct": 1, "re": "Liquidated damages set a reasonable, agreed amount of damages for delay or breach.", "rr": "Liquidated damages — заранее согласованная разумная сумма убытков за просрочку или нарушение."}, {"id": 65, "sec": "Contracts", "q": "An express warranty is one that is:", "opts": ["Implied by law", "Stated specifically by the contractor", "Provided only by the manufacturer", "Never enforceable"], "correct": 1, "re": "An express warranty is a specific promise made in writing or words.", "rr": "Express warranty — конкретное обещание, данное письменно или словами."}, {"id": 66, "sec": "Contracts", "q": "The statute of limitations for a breach of a written contract in California is generally:", "opts": ["1 year", "2 years", "4 years", "10 years"], "correct": 2, "re": "Written-contract claims generally must be brought within 4 years.", "rr": "Иск по письменному договору обычно нужно подать в течение 4 лет."}, {"id": 67, "sec": "Contracts", "q": "A home improvement contract must include a notice about:", "opts": ["The contractor's tax ID", "The buyer's right to cancel and the CSLB", "The bank's lien", "The architect's seal"], "correct": 1, "re": "HIC must contain required consumer notices, including cancellation rights and CSLB information.", "rr": "Договор HIC должен содержать обязательные уведомления потребителю, включая право отказа и сведения о CSLB."}, {"id": 68, "sec": "Contracts", "q": "'Substantial performance' generally means the contractor:", "opts": ["Did nothing", "Completed the essential purpose with only minor deviations", "Breached the contract", "Was unlicensed"], "correct": 1, "re": "Substantial performance fulfills the contract's essential purpose with only trivial, correctable defects.", "rr": "Существенное исполнение выполняет ключевую цель договора с лишь незначительными, исправимыми недочётами."}, {"id": 69, "sec": "Public Works", "q": "On public works projects, workers must generally be paid:", "opts": ["Minimum wage", "The prevailing wage", "Whatever the contract states", "Piece rate"], "correct": 1, "re": "Public works require payment of the applicable prevailing wage.", "rr": "На публичных работах обязательна оплата по установленной prevailing wage."}, {"id": 70, "sec": "Public Works", "q": "To bid or work on most public works, a contractor must be registered with the:", "opts": ["IRS", "DIR (Department of Industrial Relations)", "EPA", "CSLB only"], "correct": 1, "re": "Contractors must register with the DIR to bid on or perform public works.", "rr": "Для участия в публичных работах контрактор должен зарегистрироваться в DIR."}, {"id": 71, "sec": "Public Works", "q": "Certified payroll records on public works are submitted to verify:", "opts": ["Material costs", "That prevailing wages were paid", "Bond amounts", "Permit fees"], "correct": 1, "re": "Certified payroll documents that workers received the required prevailing wages.", "rr": "Certified payroll подтверждает, что работникам выплачена положенная prevailing wage."}, {"id": 72, "sec": "Public Works", "q": "A bid bond on a public works project guarantees that the:", "opts": ["Subs are paid", "Winning bidder will enter the contract", "Work is defect-free", "Wages are prevailing"], "correct": 1, "re": "A bid bond assures the agency the low bidder will sign the contract and post required bonds.", "rr": "Bid bond гарантирует агентству, что победитель торгов подпишет контракт и предоставит требуемые облигации."}, {"id": 73, "sec": "Public Works", "q": "Prevailing wage rates are determined by the:", "opts": ["Contractor", "Director of Industrial Relations", "Local union only", "CSLB"], "correct": 1, "re": "The DIR Director sets prevailing wage determinations by craft and locality.", "rr": "Директор DIR устанавливает prevailing wage по специальности и местности."}, {"id": 74, "sec": "Safety (Cal/OSHA)", "q": "Every California employer must have a written:", "opts": ["Marketing plan", "Injury and Illness Prevention Program (IIPP)", "Bid schedule", "Lien log"], "correct": 1, "re": "Cal/OSHA requires every employer to maintain a written IIPP.", "rr": "Cal/OSHA требует от каждого работодателя письменный IIPP."}, {"id": 75, "sec": "Safety (Cal/OSHA)", "q": "A serious injury, illness, or death at work must be reported to Cal/OSHA within:", "opts": ["8 hours", "24 hours", "48 hours", "5 days"], "correct": 0, "re": "Serious injuries/fatalities must be reported to Cal/OSHA within 8 hours.", "rr": "О серьёзной травме или гибели нужно сообщить в Cal/OSHA в течение 8 часов."}, {"id": 76, "sec": "Safety (Cal/OSHA)", "q": "'Lockout/tagout' procedures are used to:", "opts": ["Secure the job site at night", "Control hazardous energy during service/maintenance", "Lock the tool trailer", "Tag finished work"], "correct": 1, "re": "LOTO isolates and de-energizes equipment so it can't start during service.", "rr": "LOTO изолирует и обесточивает оборудование, чтобы оно не запустилось во время обслуживания."}, {"id": 77, "sec": "Safety (Cal/OSHA)", "q": "An SDS (Safety Data Sheet) provides information about:", "opts": ["Wage rates", "Hazardous chemicals and safe handling", "Bond amounts", "Building codes"], "correct": 1, "re": "SDSs describe chemical hazards, handling, and first aid under the Hazard Communication standard.", "rr": "SDS описывает опасности химикатов, обращение и первую помощь по стандарту Hazard Communication."}, {"id": 78, "sec": "Safety (Cal/OSHA)", "q": "Fall protection is generally required in construction at heights of:", "opts": ["4 feet", "6 feet", "10 feet", "20 feet"], "correct": 1, "re": "In construction, fall protection is generally required at 6 feet or more above a lower level.", "rr": "В строительстве защита от падения обычно обязательна на высоте 6 футов и выше."}, {"id": 79, "sec": "Safety (Cal/OSHA)", "q": "A 'competent person' under Cal/OSHA is someone who can:", "opts": ["Sign contracts", "Identify hazards and has authority to correct them", "Issue licenses", "Set prevailing wage"], "correct": 1, "re": "A competent person recognizes hazards and is authorized to take prompt corrective action.", "rr": "'Competent person' распознаёт опасности и уполномочен немедленно их устранять."}, {"id": 80, "sec": "Safety (Cal/OSHA)", "q": "Before disturbing more than 100 sq ft of asbestos-containing material, a contractor must be:", "opts": ["Bonded for $50,000", "Registered with Cal/OSHA for asbestos work", "Licensed as a C-22 only", "EPA 608 certified"], "correct": 1, "re": "Asbestos work over 100 sq ft requires Cal/OSHA asbestos registration (and proper certification).", "rr": "Работы с асбестом площадью более 100 кв. футов требуют регистрации Cal/OSHA по асбесту."}, {"id": 81, "sec": "Safety (Cal/OSHA)", "q": "PPE (personal protective equipment) is generally:", "opts": ["Bought by the employee", "Provided by the employer when required", "Optional always", "Only for public works"], "correct": 1, "re": "Employers must provide required PPE at no cost to employees.", "rr": "Работодатель обязан бесплатно предоставлять необходимые СИЗ работникам."}, {"id": 82, "sec": "Safety (Cal/OSHA)", "q": "A permit-required confined space is dangerous primarily because of:", "opts": ["Noise only", "Atmospheric or engulfment hazards and limited exit", "Cost", "Cold temperatures"], "correct": 1, "re": "Confined spaces pose atmospheric, engulfment, and entrapment hazards with restricted egress.", "rr": "Замкнутые пространства опасны атмосферой, засыпанием и ограниченным выходом."}, {"id": 83, "sec": "Licensing Requirements", "q": "A contractor wanting to do plumbing, electrical, and HVAC as one firm would typically hold:", "opts": ["A single C-20", "A B general building plus needed specialties, or each C-classification", "An owner-builder permit", "No license"], "correct": 1, "re": "Multiple trades require the appropriate classifications (e.g., separate C-licenses) or a qualifying general (B) where allowed.", "rr": "Несколько видов работ требуют соответствующих классификаций (отдельные C-лицензии) или генеральной B там, где это допустимо."}, {"id": 84, "sec": "Licensing Requirements", "q": "The CSLB's primary purpose is to:", "opts": ["Collect taxes", "Protect the public by regulating the construction industry", "Sell insurance", "Set union wages"], "correct": 1, "re": "The CSLB licenses and regulates contractors to protect consumers.", "rr": "CSLB лицензирует и регулирует контракторов для защиты потребителей."}, {"id": 85, "sec": "Licensing Requirements", "q": "Advertising must include the contractor's:", "opts": ["Home address", "License number", "Bond company", "Tax return"], "correct": 1, "re": "Licensed contractors must show their license number in advertising.", "rr": "Лицензированный контрактор обязан указывать номер лицензии в рекламе."}, {"id": 86, "sec": "Business Finances", "q": "Net income is:", "opts": ["Revenue before expenses", "Revenue minus all expenses and taxes", "Total assets", "Owner contributions"], "correct": 1, "re": "Net income is what remains after all expenses and taxes — the 'bottom line.'", "rr": "Чистая прибыль — то, что остаётся после всех расходов и налогов, итоговая строка."}, {"id": 87, "sec": "Business Finances", "q": "A balance sheet shows a company's financial position:", "opts": ["Over a year", "At a single point in time", "Only at tax time", "For one job"], "correct": 1, "re": "A balance sheet is a snapshot of assets, liabilities, and equity at a moment in time.", "rr": "Баланс — снимок активов, обязательств и капитала на конкретный момент."}, {"id": 88, "sec": "Employment & Labor", "q": "An apprentice on a public works job must be:", "opts": ["Unpaid", "Registered in an approved apprenticeship program", "Over 25", "A union officer"], "correct": 1, "re": "Apprentices must be enrolled in a state-approved apprenticeship program to be paid apprentice rates.", "rr": "Ученик должен быть зарегистрирован в утверждённой программе ученичества, чтобы получать ставку ученика."}, {"id": 89, "sec": "Employment & Labor", "q": "Failure to carry required workers' comp can result in:", "opts": ["A warning only", "A stop order and license suspension", "A tax credit", "Nothing"], "correct": 1, "re": "Operating without required workers' comp can trigger a stop order, penalties, and license suspension.", "rr": "Работа без обязательного workers' comp ведёт к stop order, штрафам и приостановке лицензии."}, {"id": 90, "sec": "Bonds, Insurance & Liens", "q": "A subcontractor who did NOT have a direct contract with the owner usually must serve a preliminary notice to preserve:", "opts": ["Bonding rights", "Lien and stop-payment-notice rights", "Tax rights", "License rights"], "correct": 1, "re": "Without a direct contract with the owner, the preliminary notice preserves the claimant's lien and stop-payment rights.", "rr": "Без прямого договора с владельцем предварительное уведомление сохраняет права на lien и stop payment."}, {"id": 91, "sec": "Bonds, Insurance & Liens", "q": "'Course of construction' (builder's risk) insurance covers:", "opts": ["Employee injuries", "The project itself during construction", "Auto accidents", "Contract disputes"], "correct": 1, "re": "Builder's risk insures the work/materials against loss during construction.", "rr": "Builder's risk страхует объект и материалы от потерь во время строительства."}, {"id": 92, "sec": "Contracts", "q": "If a contract term is ambiguous, courts often interpret it:", "opts": ["In favor of the contractor", "Against the party who drafted it", "As void", "In favor of the bond"], "correct": 1, "re": "Ambiguities are generally construed against the drafter.", "rr": "Неоднозначности обычно толкуются против стороны, составившей договор."}, {"id": 93, "sec": "Contracts", "q": "A unilateral mistake in a bid (e.g., math error) may allow the bidder to:", "opts": ["Never withdraw", "Seek to withdraw/rescind if conditions are met", "Double the price freely", "Ignore the bid"], "correct": 1, "re": "A genuine, material unilateral mistake promptly raised may permit rescission of the bid.", "rr": "Подлинная существенная односторонняя ошибка, заявленная быстро, может позволить отозвать заявку."}, {"id": 94, "sec": "Public Works", "q": "On public works, the agency typically awards to the:", "opts": ["Lowest responsible, responsive bidder", "Highest bidder", "First bidder", "Local bidder only"], "correct": 0, "re": "Public contracts generally go to the lowest responsible and responsive bidder.", "rr": "Публичные контракты обычно достаются самому низкому ответственному и соответствующему участнику торгов."}, {"id": 95, "sec": "Public Works", "q": "Prevailing wage generally does NOT apply to:", "opts": ["Most public works over the threshold", "Purely private residential remodels", "State building projects", "School district work"], "correct": 1, "re": "Private projects are not public works, so prevailing wage generally doesn't apply.", "rr": "Частные проекты не являются публичными работами, поэтому prevailing wage обычно не применяется."}, {"id": 96, "sec": "Safety (Cal/OSHA)", "q": "Heat illness prevention rules in California require employers to provide:", "opts": ["Only water", "Water, shade, rest, and training", "Air conditioning on site", "Bonuses"], "correct": 1, "re": "Cal/OSHA heat standards require access to water, shade, rest breaks, and training.", "rr": "Стандарты Cal/OSHA по жаре требуют воды, тени, перерывов на отдых и обучения."}, {"id": 97, "sec": "Safety (Cal/OSHA)", "q": "Scaffolding over a certain height must be:", "opts": ["Built by anyone", "Designed/inspected per Cal/OSHA and have guardrails", "Removed daily", "Bonded"], "correct": 1, "re": "Scaffolds must meet Cal/OSHA design, guardrail, and inspection requirements.", "rr": "Леса должны соответствовать требованиям Cal/OSHA по конструкции, ограждениям и осмотру."}, {"id": 98, "sec": "Licensing Requirements", "q": "An 'inactive' license means the contractor:", "opts": ["Can still bid", "Cannot contract until reactivated, but keeps the number", "Lost the license", "Owes back taxes"], "correct": 1, "re": "An inactive license preserves the number but doesn't authorize contracting until reactivated.", "rr": "Неактивная лицензия сохраняет номер, но не даёт права работать, пока не реактивирована."}, {"id": 99, "sec": "Business Finances", "q": "A break-even point is reached when:", "opts": ["Revenue exceeds assets", "Total revenue equals total costs", "Overhead is zero", "Profit is maximized"], "correct": 1, "re": "Break-even is where revenue exactly covers fixed plus variable costs — no profit, no loss.", "rr": "Точка безубыточности — где выручка точно покрывает постоянные и переменные затраты: ни прибыли, ни убытка."}, {"id": 100, "sec": "Contracts", "q": "A contractor who abandons a job without legal excuse has likely committed:", "opts": ["Substantial performance", "A material breach of contract", "A change order", "A lien waiver"], "correct": 1, "re": "Unjustified abandonment is a material breach exposing the contractor to damages.", "rr": "Необоснованное оставление работы — существенное нарушение договора, влекущее ответственность за убытки."}, {"id": 101, "sec": "Bonds, Insurance & Liens", "q": "If the OWNER records a Notice of Completion, a SUBCONTRACTOR (not the direct contractor) must record a mechanics lien within:", "opts": ["10 days", "30 days", "60 days", "90 days"], "correct": 1, "re": "With an NOC recorded, subs/suppliers get 30 days; the direct contractor gets 60 days.", "rr": "При зарегистрированном NOC у субподрядчиков/поставщиков — 30 дней; у прямого контрактора — 60 дней."}, {"id": 102, "sec": "Bonds, Insurance & Liens", "q": "With a Notice of Completion recorded, the DIRECT (prime) contractor must record a mechanics lien within:", "opts": ["30 days", "60 days", "90 days", "120 days"], "correct": 1, "re": "NOC shortens the prime contractor's window to 60 days (vs. 90 with no NOC).", "rr": "NOC сокращает срок прямого контрактора до 60 дней (против 90 без NOC)."}, {"id": 103, "sec": "Bonds, Insurance & Liens", "q": "A Notice of Cessation may be recorded by the owner after work has stopped continuously for at least:", "opts": ["7 days", "15 days", "30 days", "60 days"], "correct": 2, "re": "After 30 days of continuous cessation, the owner may record a Notice of Cessation, which (like an NOC) shortens lien windows.", "rr": "После 30 дней непрерывной остановки работ владелец может зарегистрировать Notice of Cessation, который (как NOC) сокращает сроки lien."}, {"id": 104, "sec": "Bonds, Insurance & Liens", "q": "The preliminary 20-day notice must be served on all of the following EXCEPT:", "opts": ["The owner", "The direct contractor", "The construction lender (if any)", "The county tax collector"], "correct": 3, "re": "The preliminary notice goes to the owner, the direct contractor, and the construction lender — not the tax collector.", "rr": "Предварительное уведомление направляется владельцу, прямому контрактору и кредитору стройки — но не налоговому сборщику."}, {"id": 105, "sec": "Bonds, Insurance & Liens", "q": "A direct contractor who DID contract with the owner generally:", "opts": ["Must still serve a preliminary notice on the owner", "Need not serve the owner a preliminary notice (but must notify any construction lender)", "Loses lien rights entirely", "Cannot record a lien"], "correct": 1, "re": "A direct contractor need not preliminary-notice the owner they contracted with, but must notify any construction lender.", "rr": "Прямому контрактору не нужно слать предварительное уведомление владельцу, с которым он заключил договор, но кредитора стройки уведомить надо."}, {"id": 106, "sec": "Bonds, Insurance & Liens", "q": "The amount of a mechanics lien is limited to:", "opts": ["The full contract price always", "The reasonable value of work/materials furnished or the contract price, whichever is less", "Double the unpaid balance", "Any amount the claimant chooses"], "correct": 1, "re": "A lien is limited to the lesser of the reasonable value furnished or the contract price, less amounts paid.", "rr": "Сумма lien ограничена меньшим из разумной стоимости выполненного или цены договора, за вычетом уплаченного."}, {"id": 107, "sec": "Bonds, Insurance & Liens", "q": "A 'Notice of Nonresponsibility' is used by:", "opts": ["A contractor avoiding wages", "An owner who didn't authorize a tenant's work, to protect the property from liens", "A lender", "A subcontractor"], "correct": 1, "re": "An owner records a Notice of Nonresponsibility to disclaim liability for improvements they didn't authorize (e.g., tenant work).", "rr": "Владелец регистрирует Notice of Nonresponsibility, чтобы снять с себя ответственность за работы, которые не санкционировал (например, арендатора)."}, {"id": 108, "sec": "Bonds, Insurance & Liens", "q": "A conditional lien waiver becomes effective:", "opts": ["Immediately on signing", "Only after the payment actually clears", "Never", "After 90 days"], "correct": 1, "re": "A conditional waiver is contingent on the payment actually being received/clearing.", "rr": "Условный отказ (conditional waiver) вступает в силу только после фактического получения оплаты."}, {"id": 109, "sec": "Bonds, Insurance & Liens", "q": "California's statutory lien-waiver forms include all of the following EXCEPT:", "opts": ["Conditional waiver on progress payment", "Unconditional waiver on progress payment", "Conditional waiver on final payment", "Permanent irrevocable lien"], "correct": 3, "re": "There are four statutory forms (conditional/unconditional × progress/final); 'permanent irrevocable lien' is not one.", "rr": "Есть четыре установленных формы (условный/безусловный × промежуточный/финальный); 'permanent irrevocable lien' к ним не относится."}, {"id": 110, "sec": "Bonds, Insurance & Liens", "q": "If a foreclosure suit is not filed within 90 days of recording the lien, the lien:", "opts": ["Doubles", "Becomes unenforceable/expires", "Converts to a bond", "Transfers to the lender"], "correct": 1, "re": "Failing to sue within 90 days renders the lien unenforceable and it should be released.", "rr": "Если не подать иск в течение 90 дней, lien становится неисполнимым и подлежит снятию."}, {"id": 111, "sec": "Contracts", "q": "The Subletting and Subcontracting Fair Practices Act ('Listing Law') requires a prime bidder on public works to:", "opts": ["Use only union subs", "List each sub doing more than 0.5% of the bid (or $10,000 on street/highway)", "Self-perform everything", "Pay subs in advance"], "correct": 1, "re": "Primes must list subs performing more than one-half of 1% of the total bid, to curb bid shopping.", "rr": "Генподрядчик обязан указать субов, выполняющих более 0,5% от общей заявки, чтобы пресечь bid shopping."}, {"id": 112, "sec": "Contracts", "q": "'Bid shopping' refers to a prime contractor who, after award:", "opts": ["Compares insurance quotes", "Pressures listed subs to lower prices or swaps them out improperly", "Files a lien", "Pays prevailing wage"], "correct": 1, "re": "Bid shopping is using a low bid to squeeze or replace subcontractors after the contract is awarded — restricted by the Listing Law.", "rr": "Bid shopping — давление на субов ради снижения цены или их замена после получения контракта; ограничено Listing Law."}, {"id": 113, "sec": "Contracts", "q": "Once a sub is listed, the prime may substitute that sub only:", "opts": ["At will", "For statutory cause with the awarding authority's consent", "If the price changes", "Never"], "correct": 1, "re": "Substitution of a listed sub requires a recognized statutory reason and the public agency's consent.", "rr": "Замена указанного суба требует законного основания и согласия публичного агентства."}, {"id": 114, "sec": "Contracts", "q": "A sub's bid that the prime reasonably relied on may be held to the prime under:", "opts": ["Quantum meruit", "Promissory estoppel", "Novation", "Subrogation"], "correct": 1, "re": "Promissory estoppel can bind a sub to a bid the prime reasonably relied on in its own bid.", "rr": "Promissory estoppel может связать суба его заявкой, на которую генподрядчик обоснованно полагался."}, {"id": 115, "sec": "Contracts", "q": "A 'novation' is:", "opts": ["A minor change order", "Substituting a new contract/party for an old one, with all parties' consent", "A bond claim", "A lien"], "correct": 1, "re": "Novation replaces an original contract or party with a new one by mutual agreement, extinguishing the old obligation.", "rr": "Novation заменяет исходный договор или сторону на новые по взаимному согласию, прекращая старое обязательство."}, {"id": 116, "sec": "Contracts", "q": "'Quantum meruit' allows recovery of:", "opts": ["Punitive damages", "The reasonable value of services where no enforceable price was set", "Triple damages", "Lien interest"], "correct": 1, "re": "Quantum meruit awards the reasonable value of work performed when no enforceable contract price exists.", "rr": "Quantum meruit присуждает разумную стоимость выполненной работы при отсутствии оговорённой цены."}, {"id": 117, "sec": "Contracts", "q": "A home improvement contract must contain a schedule of payments that is:", "opts": ["100% up front", "Tied to the value of work performed and materials delivered", "Paid only at the end", "Set by the lender"], "correct": 1, "re": "HIC payments must reasonably correspond to work performed and materials delivered — not front-loaded.", "rr": "Платежи по HIC должны разумно соответствовать выполненной работе и поставленным материалам, без переплат вперёд."}, {"id": 118, "sec": "Contracts", "q": "For service and repair contracts (specific exemption), the cash down payment limit is generally:", "opts": ["No special limit beyond the $1,000/10% HIC rule unless service-and-repair conditions are met", "Always 50%", "Always $5,000", "Zero"], "correct": 0, "re": "Standard HIC down-payment caps apply unless the strict statutory 'service and repair' conditions are met.", "rr": "Действуют стандартные лимиты аванса HIC, если не соблюдены строгие условия 'service and repair' по закону."}, {"id": 119, "sec": "Contracts", "q": "A 'Mechanics Lien Warning' notice must be given to the owner:", "opts": ["After completion", "As part of the home improvement contract documents", "Only on public works", "Never"], "correct": 1, "re": "HIC paperwork must include the required notice informing owners about mechanics lien rights of subs/suppliers.", "rr": "Документы HIC должны включать уведомление, информирующее владельца о правах субов/поставщиков на mechanics lien."}, {"id": 120, "sec": "Licensing Requirements", "q": "Under B&P Code §7000s, the registrar may issue a citation that includes:", "opts": ["Jail time", "An order of correction and a civil penalty", "License revocation only", "Criminal fines only"], "correct": 1, "re": "A CSLB citation may order correction and assess a civil penalty without a full disciplinary hearing.", "rr": "Цитата CSLB может предписать исправление и назначить гражданский штраф без полноценного дисциплинарного слушания."}, {"id": 121, "sec": "Licensing Requirements", "q": "'Abandonment' of a construction project without legal excuse is, under the license law:", "opts": ["Allowed if paid", "Grounds for disciplinary action against the license", "A felony always", "Only a contract issue"], "correct": 1, "re": "Willful abandonment is a statutory ground for CSLB discipline.", "rr": "Умышленное оставление проекта — установленное основание для дисциплинарных мер CSLB."}, {"id": 122, "sec": "Licensing Requirements", "q": "Departure from accepted trade standards ('departure from plans/specs') is disciplinable when it is:", "opts": ["Any deviation", "Willful or fraudulent and causes harm", "Approved by the owner", "A minor cosmetic change"], "correct": 1, "re": "Willful departure from plans/specs or trade standards, causing injury, is grounds for discipline.", "rr": "Умышленное отступление от планов/спецификаций или стандартов, причинившее вред, — основание для дисциплинарных мер."}, {"id": 123, "sec": "Licensing Requirements", "q": "Aiding an unlicensed person to evade the license law is:", "opts": ["Permitted for friends", "A violation that can lead to discipline", "Allowed under $5,000", "Encouraged by CSLB"], "correct": 1, "re": "Helping an unlicensed person contract is itself a violation of the license law.", "rr": "Помощь безлицензионному лицу заключать контракты — само по себе нарушение закона о лицензировании."}, {"id": 124, "sec": "Licensing Requirements", "q": "The CSLB may suspend a license automatically for an unsatisfied:", "opts": ["Parking ticket", "Construction-related court judgment not paid within 90 days", "Marketing complaint", "Late tax filing"], "correct": 1, "re": "An unpaid construction-related judgment can trigger automatic suspension if not resolved within 90 days.", "rr": "Неоплаченное судебное решение по строительству может вызвать автоматическую приостановку, если не урегулировано за 90 дней."}, {"id": 125, "sec": "Licensing Requirements", "q": "A 'disciplinary bond' may be required by the registrar when a contractor:", "opts": ["Renews on time", "Has a history of violations/has been disciplined", "Is newly licensed only", "Carries GL insurance"], "correct": 1, "re": "A disciplinary bond can be imposed on licensees with a record of violations as a condition of licensure.", "rr": "Disciplinary bond может назначаться лицензиатам с историей нарушений как условие лицензии."}, {"id": 126, "sec": "Licensing Requirements", "q": "The statute of limitations for the CSLB to bring most disciplinary actions is generally within:", "opts": ["1 year of the act", "4 years of the act (or 2 years for some), with discovery rules", "10 years", "No limit ever"], "correct": 1, "re": "CSLB discipline generally must begin within set periods (often within four years of the act, subject to discovery rules).", "rr": "Дисциплинарные дела CSLB обычно нужно начать в установленные сроки (часто в течение 4 лет, с учётом правил обнаружения)."}, {"id": 127, "sec": "Business Finances", "q": "A contractor's overhead is $90,000/year and target net profit is $30,000. To cover both on $600,000 of direct job costs, the needed markup is about:", "opts": ["10%", "20%", "25%", "33%"], "correct": 1, "re": "($90k + $30k) ÷ $600k = 20% markup on costs.", "rr": "($90k + $30k) ÷ $600k = 20% наценки на затраты."}, {"id": 128, "sec": "Business Finances", "q": "If a job sells for $10,000 with a 25% margin (on price), the cost was:", "opts": ["$7,000", "$7,500", "$8,000", "$8,500"], "correct": 1, "re": "Margin on price: cost = $10,000 × (1 − 0.25) = $7,500.", "rr": "Маржа от цены: себестоимость = $10,000 × (1 − 0,25) = $7,500."}, {"id": 129, "sec": "Business Finances", "q": "Markup and margin differ because markup is figured on ____ and margin on ____:", "opts": ["price; cost", "cost; selling price", "profit; revenue", "tax; income"], "correct": 1, "re": "Markup is a percentage of cost; margin is a percentage of selling price.", "rr": "Наценка — процент от себестоимости; маржа — процент от цены продажи."}, {"id": 130, "sec": "Business Finances", "q": "'Retention' (retainage) on a contract is:", "opts": ["Tax withheld", "A percentage of progress payments held back until completion", "A bond", "Overtime"], "correct": 1, "re": "Retention is a portion of each payment withheld to ensure completion, released at the end.", "rr": "Retention — часть каждого платежа, удержанная до завершения и выплачиваемая в конце."}, {"id": 131, "sec": "Business Finances", "q": "A contractor using the 'completed-contract' method recognizes profit:", "opts": ["As cash arrives", "When the contract is substantially complete", "Monthly", "At signing"], "correct": 1, "re": "Completed-contract defers profit recognition until the job is essentially done.", "rr": "Метод completed-contract откладывает признание прибыли до фактического завершения работ."}, {"id": 132, "sec": "Business Finances", "q": "The 'percentage-of-completion' method recognizes revenue:", "opts": ["Only at the end", "In proportion to work completed over the contract", "Never", "At bid time"], "correct": 1, "re": "Percentage-of-completion books revenue as the project progresses.", "rr": "Метод percentage-of-completion признаёт выручку по мере выполнения проекта."}, {"id": 133, "sec": "Business Finances", "q": "Estimated quarterly tax payments to the IRS are generally required for:", "opts": ["W-2 employees", "Self-employed/owners expecting to owe $1,000+ in tax", "Apprentices", "Bondholders"], "correct": 1, "re": "Self-employed individuals generally pay estimated taxes quarterly when they expect to owe $1,000 or more.", "rr": "Самозанятые обычно платят расчётный налог поквартально, если ожидают долг $1,000+."}, {"id": 134, "sec": "Employment & Labor", "q": "On the 7th consecutive day of work in a workweek, the first 8 hours are paid at:", "opts": ["Straight time", "1.5×", "2×", "No pay"], "correct": 1, "re": "The first 8 hours on the 7th consecutive day are at 1.5×; over 8 that day is 2×.", "rr": "Первые 8 часов в 7-й день подряд — 1.5×; свыше 8 в этот день — 2×."}, {"id": 135, "sec": "Employment & Labor", "q": "An employer must register with the EDD after paying wages over ____ in a calendar quarter:", "opts": ["$100", "$500", "$1,000", "$5,000"], "correct": 0, "re": "Once an employer pays over $100 in wages in a quarter, it must register with the EDD.", "rr": "Выплатив более $100 зарплаты за квартал, работодатель обязан зарегистрироваться в EDD."}, {"id": 136, "sec": "Employment & Labor", "q": "Form DE 9 / DE 9C filed with the EDD reports:", "opts": ["Federal income tax only", "Quarterly wages and state payroll taxes", "Sales tax", "Mechanics liens"], "correct": 1, "re": "The DE 9 and DE 9C report quarterly wages and California payroll tax contributions.", "rr": "DE 9 и DE 9C отражают квартальную зарплату и взносы по налогам на зарплату Калифорнии."}, {"id": 137, "sec": "Employment & Labor", "q": "A 'waiting time penalty' for late final wages can be up to:", "opts": ["1 day's pay", "8 hours' pay", "30 days' wages", "One year's wages"], "correct": 2, "re": "Willfully late final wages can cost up to 30 days of the employee's daily wage.", "rr": "Умышленная задержка окончательного расчёта может стоить до 30 дней дневной зарплаты работника."}, {"id": 138, "sec": "Employment & Labor", "q": "Under the ABC test, prong 'B' requires the worker to perform work that is:", "opts": ["Inside the hirer's usual business", "Outside the hiring entity's usual course of business", "On public works", "For union members"], "correct": 1, "re": "Prong B requires the work be outside the hirer's usual business to be an independent contractor.", "rr": "Условие B требует, чтобы работа была вне обычной деятельности нанимателя — иначе это сотрудник."}, {"id": 139, "sec": "Employment & Labor", "q": "Overtime exemptions (e.g., 'executive') generally require the employee to:", "opts": ["Just have a title", "Meet salary AND duties tests", "Work part-time", "Be on public works"], "correct": 1, "re": "Exempt status requires meeting both a minimum salary threshold and specific duties tests.", "rr": "Освобождение от сверхурочных требует и минимальной зарплаты, и выполнения конкретных обязанностей (duties test)."}, {"id": 140, "sec": "Employment & Labor", "q": "An employer who pays cash 'under the table' to avoid payroll taxes risks:", "opts": ["Nothing", "Tax fraud charges, penalties, and license discipline", "A refund", "A bonus"], "correct": 1, "re": "Off-the-books cash payroll exposes the employer to tax fraud, penalties, and CSLB discipline.", "rr": "Зарплата 'в конверте' грозит обвинением в налоговом мошенничестве, штрафами и дисциплинарными мерами CSLB."}, {"id": 141, "sec": "Employment & Labor", "q": "Paid sick leave in California generally accrues at a minimum of:", "opts": ["1 hour per 10 hours worked", "1 hour per 30 hours worked", "1 day per month", "Only for full-time"], "correct": 1, "re": "Statewide paid sick leave accrues at least 1 hour for every 30 hours worked (verify current local minimums).", "rr": "Оплачиваемый больничный по штату начисляется минимум 1 час за каждые 30 отработанных часов (сверь местные нормы)."}, {"id": 142, "sec": "Employment & Labor", "q": "Form W-2 must be furnished to employees by:", "opts": ["April 15", "January 31", "June 30", "December 31"], "correct": 1, "re": "Employers must provide W-2s to employees by January 31.", "rr": "Работодатель обязан выдать W-2 работникам до 31 января."}, {"id": 143, "sec": "Public Works", "q": "On public works, the threshold above which contractor DIR registration is generally required for new projects is about:", "opts": ["$0", "$15,000 (and $25,000 for awards), subject to current law", "$100,000", "$1 million"], "correct": 1, "re": "Small-project exemptions exist (roughly $15,000 work / $25,000 award thresholds) — verify current figures.", "rr": "Есть исключения для малых проектов (примерно $15,000 работ / $25,000 контракт) — проверь актуальные цифры."}, {"id": 144, "sec": "Public Works", "q": "Certified payroll on public works must generally be submitted:", "opts": ["Once at the end", "Weekly (or per agency schedule) via the DIR eCPR system", "Annually", "Never"], "correct": 1, "re": "Contractors submit certified payroll records (often weekly) electronically through DIR.", "rr": "Контракторы подают certified payroll (часто еженедельно) электронно через DIR."}, {"id": 145, "sec": "Public Works", "q": "Prevailing wage includes the basic hourly rate PLUS:", "opts": ["Only overtime", "Fringe benefits (health, pension, training)", "Sales tax", "Bond premiums"], "correct": 1, "re": "Prevailing wage is the basic rate plus required fringe benefit contributions.", "rr": "Prevailing wage — это базовая ставка плюс обязательные взносы на льготы (мед., пенсия, обучение)."}, {"id": 146, "sec": "Public Works", "q": "Failure to pay prevailing wages can result in:", "opts": ["A thank-you letter", "Penalties, back wages, and debarment from public works", "A tax credit", "A larger bond return"], "correct": 1, "re": "Underpaying prevailing wages can bring penalties, restitution, and debarment from bidding public works.", "rr": "Недоплата prevailing wage влечёт штрафы, возмещение и отстранение (debarment) от публичных торгов."}, {"id": 147, "sec": "Public Works", "q": "A Stop Payment Notice on a PUBLIC works project is served on the:", "opts": ["County recorder", "Public entity holding the funds", "Bonding company", "Subcontractor"], "correct": 1, "re": "On public works there are no liens against the property; a stop payment notice reaches funds held by the public entity.", "rr": "На публичных работах нет lien на имущество; stop payment notice достаёт средства, удерживаемые публичным органом."}, {"id": 148, "sec": "Public Works", "q": "On public works, instead of a mechanics lien, an unpaid sub typically pursues the:", "opts": ["Property title", "Payment bond and/or stop payment notice", "Owner's home", "CSLB bond only"], "correct": 1, "re": "Public property can't be liened; remedies are the statutory payment bond and stop payment notice.", "rr": "Публичную собственность нельзя обременить lien; средства защиты — payment bond и stop payment notice."}, {"id": 149, "sec": "Bonds, Insurance & Liens", "q": "A 'Little Miller Act' payment bond on California public works protects:", "opts": ["The agency only", "Subcontractors and suppliers who go unpaid", "The bonding company", "Taxpayers from cost overruns"], "correct": 1, "re": "The payment bond required on public works secures payment to subs and suppliers.", "rr": "Payment bond на публичных работах обеспечивает оплату субам и поставщикам."}, {"id": 150, "sec": "Bonds, Insurance & Liens", "q": "A claim against a contractor's CSLB bond is generally limited to harm caused by:", "opts": ["Any contract dispute", "Specified violations of the license law (e.g., to consumers/employees)", "Marketing", "Tax issues"], "correct": 1, "re": "The contractor's bond covers specific statutory violations harming homeowners, employees, and certain others.", "rr": "Облигация контрактора покрывает конкретные нарушения закона, навредившие домовладельцам, работникам и некоторым другим."}, {"id": 151, "sec": "Contracts", "q": "A 'time is of the essence' clause means:", "opts": ["Deadlines are flexible", "Timely performance is a material term; lateness is a breach", "Only the price matters", "The bond controls timing"], "correct": 1, "re": "This clause makes the completion dates material, so delay is a breach.", "rr": "Эта оговорка делает сроки существенным условием, поэтому просрочка — нарушение."}, {"id": 152, "sec": "Contracts", "q": "A contract provision requiring disputes to go to a neutral third party's binding decision is:", "opts": ["Mediation", "Arbitration", "Litigation", "Estoppel"], "correct": 1, "re": "Arbitration submits the dispute to a neutral whose decision is typically binding.", "rr": "Арбитраж передаёт спор нейтральному лицу, решение которого обычно обязательно."}, {"id": 153, "sec": "Contracts", "q": "Mediation differs from arbitration because mediation is:", "opts": ["Binding", "Non-binding; the mediator helps parties reach their own agreement", "Decided by a judge", "Only for public works"], "correct": 1, "re": "A mediator facilitates a voluntary settlement and does not impose a decision.", "rr": "Медиатор помогает сторонам добровольно договориться и не выносит обязательного решения."}, {"id": 154, "sec": "Contracts", "q": "The 'parol evidence rule' limits use of:", "opts": ["Bond claims", "Prior oral statements to contradict a complete written contract", "Lien notices", "Change orders"], "correct": 1, "re": "Parol evidence generally bars prior/contemporaneous oral terms that contradict a fully integrated written contract.", "rr": "Правило parol evidence обычно запрещает устные договорённости, противоречащие полному письменному договору."}, {"id": 155, "sec": "Contracts", "q": "An 'implied warranty of merchantability' means goods/materials are:", "opts": ["Free", "Fit for their ordinary purpose", "Always custom", "Tax-exempt"], "correct": 1, "re": "Merchantable goods are reasonably fit for the ordinary purposes for which they're used.", "rr": "Товар признаётся merchantable, если разумно пригоден для обычного использования."}, {"id": 156, "sec": "Contracts", "q": "A contractor's standard workmanship warranty in California is often expressed as:", "opts": ["No warranty", "One year, separate from statutory defect limitations", "Lifetime always", "Only what the bond covers"], "correct": 1, "re": "Contractors commonly warrant workmanship (e.g., 1 year), in addition to statutory limitation periods for defects.", "rr": "Контракторы обычно дают гарантию на работу (например, 1 год), помимо законных сроков по дефектам."}, {"id": 157, "sec": "Contracts", "q": "For latent (hidden) construction defects, California's statute of repose is generally:", "opts": ["1 year", "4 years", "10 years", "No limit"], "correct": 2, "re": "Latent defect claims generally must be brought within 10 years of substantial completion.", "rr": "Иски по скрытым дефектам обычно нужно подать в течение 10 лет с момента существенного завершения."}, {"id": 158, "sec": "Contracts", "q": "For patent (obvious) construction defects, the limitations period is generally:", "opts": ["1 year", "4 years", "10 years", "20 years"], "correct": 1, "re": "Patent defects generally have a 4-year limitations period.", "rr": "По явным (patent) дефектам обычно действует срок 4 года."}, {"id": 159, "sec": "Contracts", "q": "The 'Right to Repair Act' (SB 800) primarily governs:", "opts": ["Public works wages", "Residential new-construction defect claims and a pre-litigation process", "Commercial leases", "Auto repair"], "correct": 1, "re": "SB 800 sets standards and a notice-and-repair process for defects in new residential construction.", "rr": "SB 800 устанавливает стандарты и процедуру 'уведомление-ремонт' по дефектам нового жилого строительства."}, {"id": 160, "sec": "Contracts", "q": "A liquidated damages clause is unenforceable if the stated amount is:", "opts": ["A reasonable estimate", "An unreasonable penalty far exceeding likely harm", "Per day", "Agreed in writing"], "correct": 1, "re": "Liquidated damages must be a reasonable forecast of harm; a punitive amount is unenforceable.", "rr": "Liquidated damages должны быть разумной оценкой ущерба; карательная сумма не имеет силы."}, {"id": 161, "sec": "Licensing Requirements", "q": "A contractor who allows another person to use their license number to pull permits is engaged in:", "opts": ["A legal arrangement", "Unlawful 'license renting,' a serious violation", "Joint venture licensing", "An RME setup"], "correct": 1, "re": "Lending or 'renting' a license number is a serious violation of the license law.", "rr": "Сдача 'в аренду' номера лицензии — серьёзное нарушение закона о лицензировании."}, {"id": 162, "sec": "Licensing Requirements", "q": "To add a classification to an existing license, the qualifier generally must:", "opts": ["Pay a fee only", "Pass the trade exam for that classification (unless waived)", "Wait 5 years", "Form a new corporation"], "correct": 1, "re": "A new classification typically requires passing the relevant trade exam (with limited waivers).", "rr": "Новая классификация обычно требует сдачи соответствующего trade exam (с редкими исключениями)."}, {"id": 163, "sec": "Licensing Requirements", "q": "An owner-builder exemption generally does NOT apply when the owner:", "opts": ["Builds for personal use and doesn't sell quickly", "Builds intending to sell, exceeding the statutory limits", "Hires licensed subs", "Lives in the home"], "correct": 1, "re": "The owner-builder exemption is limited; building structures for sale beyond statutory limits requires a license.", "rr": "Освобождение owner-builder ограничено; строительство на продажу сверх установленных лимитов требует лицензии."}, {"id": 164, "sec": "Employment & Labor", "q": "A contractor must keep payroll records for at least (commonly):", "opts": ["30 days", "6 months", "3–4 years (verify by record type)", "No requirement"], "correct": 2, "re": "Payroll and tax records are generally retained for several years (often 3–4); verify by record type and agency.", "rr": "Зарплатные и налоговые записи обычно хранят несколько лет (часто 3–4); уточняй по типу записи и органу."}, {"id": 165, "sec": "Employment & Labor", "q": "An employer's responsibility for an employee's negligent acts within the scope of employment is:", "opts": ["Estoppel", "Respondeat superior (vicarious liability)", "Novation", "Subrogation"], "correct": 1, "re": "Under respondeat superior, employers are vicariously liable for employees' on-the-job negligence.", "rr": "По доктрине respondeat superior работодатель несёт субсидиарную ответственность за служебную небрежность работника."}, {"id": 166, "sec": "Bonds, Insurance & Liens", "q": "'Subrogation' in insurance means the insurer:", "opts": ["Cancels the policy", "Steps into the insured's rights to recover from the at-fault party", "Doubles the premium", "Issues a bond"], "correct": 1, "re": "After paying a claim, the insurer is subrogated to the insured's recovery rights against the responsible party.", "rr": "Выплатив возмещение, страховщик получает право требования застрахованного к виновной стороне (суброгация)."}, {"id": 167, "sec": "Bonds, Insurance & Liens", "q": "An 'additional insured' endorsement typically:", "opts": ["Insures the contractor's truck", "Extends a policy's coverage to another party (e.g., the owner/GC)", "Replaces workers' comp", "Pays liens"], "correct": 1, "re": "It extends the named policy's protection to another party, common in subcontract requirements.", "rr": "Эндорсмент 'additional insured' распространяет защиту полиса на другую сторону — частое требование к субам."}, {"id": 168, "sec": "Bonds, Insurance & Liens", "q": "A 'certificate of insurance' is:", "opts": ["The full policy", "Proof of coverage summary, not the policy itself", "A bond", "A lien waiver"], "correct": 1, "re": "A COI summarizes coverage but does not by itself confer or replace the policy terms.", "rr": "COI лишь подтверждает наличие страховки сводкой, но не заменяет сам полис."}, {"id": 169, "sec": "Business Finances", "q": "A 'profit & overhead' (P&O / 'O&P') markup on insurance-restoration work is commonly cited as:", "opts": ["5%", "10% and 10% (≈20%)", "50%", "100%"], "correct": 1, "re": "The traditional general-contractor O&P on restoration is often cited as 10% overhead + 10% profit.", "rr": "Традиционный O&P генподрядчика на восстановительных работах часто указывают как 10% накладных + 10% прибыли."}, {"id": 170, "sec": "Business Finances", "q": "A contractor's 'cost of goods sold' on a job would include:", "opts": ["Office rent", "Direct labor, materials, and subcontracts for that job", "The owner's salary", "Marketing"], "correct": 1, "re": "COGS captures the direct job costs: labor, materials, equipment, and subs for that project.", "rr": "COGS включает прямые затраты по заказу: труд, материалы, оборудование и субподряд по этому проекту."}, {"id": 171, "sec": "Contracts", "q": "A 'pay-when-paid' clause is generally interpreted in California as:", "opts": ["A condition that erases the sub's right to payment", "A reasonable-time provision; the sub must still eventually be paid", "Always void", "Identical to pay-if-paid and enforceable"], "correct": 1, "re": "California disfavors true 'pay-if-paid' conditions; 'pay-when-paid' is read as allowing a reasonable time to pay.", "rr": "Калифорния не одобряет настоящие 'pay-if-paid'; 'pay-when-paid' трактуется как разумный срок оплаты, но платить всё равно надо."}, {"id": 172, "sec": "Contracts", "q": "A contractor may NOT enforce a contract clause that requires the buyer to waive:", "opts": ["The down payment", "Statutory consumer protections / lien rights in advance, where prohibited", "The completion date", "The warranty"], "correct": 1, "re": "Advance waivers of certain statutory protections (e.g., lien rights) are unenforceable where the law forbids them.", "rr": "Предварительный отказ от ряда законных защит (например, прав на lien) недействителен там, где закон это запрещает."}, {"id": 173, "sec": "Public Works", "q": "A 'project labor agreement' (PLA) on public works is:", "opts": ["A bond", "A pre-hire collective bargaining agreement setting terms for the project", "A lien", "A permit"], "correct": 1, "re": "A PLA is a pre-hire agreement establishing labor terms for a specific public project.", "rr": "PLA — предварительное соглашение, устанавливающее трудовые условия для конкретного публичного проекта."}, {"id": 174, "sec": "Public Works", "q": "Apprenticeship 'ratio' requirements on public works mean:", "opts": ["No apprentices allowed", "A set ratio of apprentice-to-journeyman hours must be met", "Only journeymen work", "Apprentices are unpaid"], "correct": 1, "re": "Public works often require employing apprentices at a defined ratio to journeyman hours.", "rr": "На публичных работах часто требуется нанимать учеников в заданном соотношении к часам journeyman."}, {"id": 175, "sec": "Safety (Cal/OSHA)", "q": "A Cal/OSHA 'serious violation' citation means:", "opts": ["A paperwork error", "A substantial probability of death or serious physical harm", "A minor housekeeping issue", "An advertising mistake"], "correct": 1, "re": "A serious violation involves a realistic probability of death or serious physical harm.", "rr": "'Serious violation' Cal/OSHA означает реальную вероятность смерти или серьёзного вреда здоровью."}, {"id": 176, "sec": "Safety (Cal/OSHA)", "q": "A 'willful' Cal/OSHA violation carries higher penalties because the employer:", "opts": ["Made an honest mistake", "Knew of the requirement and intentionally disregarded it", "Was a small business", "Had no employees"], "correct": 1, "re": "Willful violations involve intentional disregard or plain indifference to a known requirement.", "rr": "Willful-нарушение — умышленное игнорирование или явное безразличие к известному требованию."}, {"id": 177, "sec": "Safety (Cal/OSHA)", "q": "Cal/OSHA Form 300 is used to:", "opts": ["File taxes", "Log recordable work-related injuries and illnesses", "Apply for a license", "Record liens"], "correct": 1, "re": "The Form 300 log records work-related injuries and illnesses; the 300A is the annual summary.", "rr": "Журнал Form 300 фиксирует производственные травмы и болезни; 300A — годовая сводка."}, {"id": 178, "sec": "Safety (Cal/OSHA)", "q": "Excavations 5 feet or deeper generally require:", "opts": ["No precautions", "A protective system (sloping, shoring, or shielding) unless stable rock", "A bond", "A permit only"], "correct": 1, "re": "Trenches/excavations 5 ft+ need cave-in protection unless made entirely in stable rock.", "rr": "Траншеи/котлованы от 5 футов требуют защиты от обрушения, кроме случаев в устойчивой скале."}, {"id": 179, "sec": "Safety (Cal/OSHA)", "q": "A Cal/OSHA excavation permit is generally required for trenches deeper than:", "opts": ["3 feet", "5 feet", "10 feet (for permit; protection still needed at 5 ft)", "20 feet"], "correct": 2, "re": "A Cal/OSHA permit is generally required for trenches/excavations 5 ft deep where workers enter; an annual permit covers most; project permits apply to deeper work (verify current rule).", "rr": "Разрешение Cal/OSHA обычно нужно для траншей, куда заходят люди; защита нужна от 5 футов, отдельные разрешения — для глубоких работ (сверь актуальные нормы)."}, {"id": 180, "sec": "Safety (Cal/OSHA)", "q": "Before digging, a contractor must contact the regional notification center (call/click 811) to:", "opts": ["Order materials", "Have underground utilities marked (DigAlert)", "Get a license", "File a lien"], "correct": 1, "re": "Calling 811/DigAlert before excavation has utilities located and marked to prevent strikes.", "rr": "Звонок 811/DigAlert до раскопок обеспечивает разметку подземных коммуникаций, чтобы их не повредить."}, {"id": 181, "sec": "Licensing Requirements", "q": "If a corporation's only qualifying RMO leaves, the license is:", "opts": ["Unaffected", "Subject to suspension if not replaced within the allowed period", "Automatically revoked same day", "Converted to a sole prop"], "correct": 1, "re": "Losing the qualifier can lead to suspension if a replacement isn't reported within the statutory window (e.g., 90 days).", "rr": "Уход квалификатора может привести к приостановке, если замену не заявить в установленный срок (например, 90 дней)."}, {"id": 182, "sec": "Licensing Requirements", "q": "A contractor must report a conviction or specified adverse license action to CSLB because:", "opts": ["It's optional", "Failure to disclose is itself a violation", "CSLB never asks", "Only felonies matter for ads"], "correct": 1, "re": "Licensees have a duty to report certain convictions/actions; concealment is a violation.", "rr": "Лицензиат обязан сообщать об определённых судимостях/санкциях; сокрытие — нарушение."}, {"id": 183, "sec": "Business Finances", "q": "A 'fixed-price' (lump-sum) contract places the risk of cost overruns mainly on the:", "opts": ["Owner", "Contractor", "Lender", "Bond company"], "correct": 1, "re": "In a lump-sum contract, the contractor bears overrun risk for the agreed scope.", "rr": "В договоре с фиксированной ценой риск перерасхода в рамках согласованного объёма несёт контрактор."}, {"id": 184, "sec": "Business Finances", "q": "A 'cost-plus' contract reimburses costs plus a fee, shifting overrun risk toward the:", "opts": ["Contractor", "Owner", "Subcontractor", "Insurer"], "correct": 1, "re": "Cost-plus shifts more cost-overrun risk to the owner, who pays actual costs plus the fee.", "rr": "Cost-plus переносит риск перерасхода на владельца, который платит фактические затраты плюс гонорар."}, {"id": 185, "sec": "Contracts", "q": "A 'scope of work' that is vague most often leads to:", "opts": ["Lower price", "Disputes and change-order conflicts", "Faster completion", "Bond claims by owner"], "correct": 1, "re": "Vague scope breeds disagreement over what's included, driving disputes and change orders.", "rr": "Размытый объём работ порождает споры о включённом и провоцирует change orders."}, {"id": 186, "sec": "Contracts", "q": "In a home improvement contract, the total contract price must be:", "opts": ["Estimated only", "Stated as a specific dollar amount (or a clear method to compute it)", "Hidden until completion", "Set by the lender"], "correct": 1, "re": "HICs must state the total price clearly so the consumer knows the full cost.", "rr": "HIC должен ясно указывать общую цену, чтобы потребитель знал полную стоимость."}, {"id": 187, "sec": "Employment & Labor", "q": "Independent-contractor status is LEAST supported when the worker:", "opts": ["Has their own license and tools", "Sets their own hours", "Works only for one hirer, doing the hirer's core work, under direction", "Invoices for projects"], "correct": 2, "re": "Working solely for one hirer, on its core business, under its control points to employee status.", "rr": "Работа только на одного нанимателя, по его основной деятельности и под его контролем указывает на статус сотрудника."}, {"id": 188, "sec": "Employment & Labor", "q": "A C-20 contractor hiring helpers and paying them hourly under his direction has created:", "opts": ["Independent contractors", "An employer-employee relationship requiring payroll compliance", "A partnership", "A joint venture"], "correct": 1, "re": "Hourly helpers under the contractor's control are employees, triggering payroll tax and workers' comp duties.", "rr": "Помощники на почасовой оплате под контролем контрактора — сотрудники, что влечёт обязанности по налогам и workers' comp."}, {"id": 189, "sec": "Bonds, Insurance & Liens", "q": "A contractor's failure to maintain the required bond results in:", "opts": ["A warning only", "License suspension until the bond is restored", "A tax penalty", "Nothing"], "correct": 1, "re": "The license is suspended if the required bond lapses, until coverage is reinstated.", "rr": "При прекращении обязательной облигации лицензия приостанавливается до её восстановления."}, {"id": 190, "sec": "Bonds, Insurance & Liens", "q": "A 'completion bond' differs from a performance bond in that it primarily assures:", "opts": ["Sub payment", "The lender/owner the project will be finished free of liens", "Prevailing wage", "The bid price"], "correct": 1, "re": "A completion bond assures financing parties the project will be completed and lien-free.", "rr": "Completion bond гарантирует финансирующим сторонам завершение проекта без обременений lien."}, {"id": 191, "sec": "Public Works", "q": "On public works, falsifying certified payroll is:", "opts": ["A clerical issue", "A serious offense that can lead to penalties, debarment, and criminal exposure", "Encouraged", "Allowed under $25,000"], "correct": 1, "re": "Falsifying certified payroll can bring civil penalties, debarment, and criminal liability.", "rr": "Подделка certified payroll грозит гражданскими штрафами, debarment и уголовной ответственностью."}, {"id": 192, "sec": "Public Works", "q": "A public agency may withhold contract payments to enforce:", "opts": ["Marketing rules", "Prevailing wage and labor compliance", "Bond renewals", "License ads"], "correct": 1, "re": "Agencies can withhold payments to secure prevailing-wage and labor-law compliance.", "rr": "Агентство может удерживать платежи для обеспечения соблюдения prevailing wage и трудового законодательства."}, {"id": 193, "sec": "Safety (Cal/OSHA)", "q": "Respirator use on a job that has respiratory hazards requires:", "opts": ["Any mask", "A written respiratory protection program with fit testing and medical evaluation", "Nothing for short tasks", "Only eye protection"], "correct": 1, "re": "Required respirator use triggers a written program, medical clearance, and fit testing.", "rr": "Обязательное использование респиратора требует письменной программы, медзаключения и fit testing."}, {"id": 194, "sec": "Safety (Cal/OSHA)", "q": "The Hazard Communication standard's 'right to know' covers employees' access to:", "opts": ["Payroll", "Chemical hazard info, labels, and SDSs", "Bond details", "Bid results"], "correct": 1, "re": "HazCom guarantees workers information about chemical hazards via labels, SDSs, and training.", "rr": "HazCom гарантирует работникам сведения об опасных химикатах через маркировку, SDS и обучение."}, {"id": 195, "sec": "Safety (Cal/OSHA)", "q": "GFCI protection on construction sites is required to prevent:", "opts": ["Overtime", "Electric shock from ground faults", "Theft", "Noise"], "correct": 1, "re": "Ground-fault circuit interrupters protect workers from shock due to ground faults.", "rr": "GFCI защищают работников от удара током при замыкании на землю."}, {"id": 196, "sec": "Licensing Requirements", "q": "The 'Contractors State License Law' is found primarily in the California:", "opts": ["Penal Code", "Business and Professions Code (§7000 et seq.)", "Vehicle Code", "Tax Code"], "correct": 1, "re": "The license law is in B&P Code beginning at §7000.", "rr": "Закон о лицензировании контракторов — в Business and Professions Code начиная с §7000."}, {"id": 197, "sec": "Business Finances", "q": "A contractor who consistently underbids and runs out of cash mid-project most likely failed at:", "opts": ["Marketing", "Estimating and cash-flow planning", "Safety", "Lien filing"], "correct": 1, "re": "Chronic underbidding and cash shortfalls point to weak estimating and cash-flow management.", "rr": "Хронический недобор цены и нехватка денег указывают на слабую смету и планирование денежного потока."}, {"id": 198, "sec": "Contracts", "q": "An 'integration clause' in a contract states that the written document:", "opts": ["Can be changed orally anytime", "Is the complete and final agreement of the parties", "Is only an estimate", "Needs no signatures"], "correct": 1, "re": "An integration (merger) clause confirms the writing is the parties' complete final agreement.", "rr": "Integration (merger) clause подтверждает, что письменный документ — полное и окончательное соглашение сторон."}, {"id": 199, "sec": "Bonds, Insurance & Liens", "q": "A contractor who pulls a permit but lets an unlicensed person do the actual contracting may face:", "opts": ["No issue", "Discipline for aiding unlicensed activity and license-law violations", "A tax refund", "A bond increase only"], "correct": 1, "re": "Fronting permits for unlicensed work violates the license law and invites discipline.", "rr": "Получение разрешений ради безлицензионной работы нарушает закон и ведёт к дисциплинарным мерам."}, {"id": 200, "sec": "Contracts", "q": "The single best protection against payment disputes on a home improvement job is a:", "opts": ["Verbal promise", "Clear written contract with defined scope, price, and payment schedule", "Larger down payment", "Bigger bond"], "correct": 1, "re": "A clear, complete written contract aligned to work performed is the strongest defense against payment disputes.", "rr": "Чёткий и полный письменный договор, привязанный к выполненной работе, — лучшая защита от споров об оплате."}];
